import streamlit as st

st.set_page_config(page_title="Happy Birthday Hani", page_icon="💌", layout="centered")

if "open" not in st.session_state:
    st.session_state.open = False

HAN1 = ""
HAN2 = ""
HAN3 = ""

st.markdown("""
<style>
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;1,400&family=Poppins:wght@300;400;500&display=swap');
.stApp, [data-testid=\"stAppViewContainer\"], section.main > div { background-color: #FFD6E0 !important; }
[data-testid=\"stHeader\"] { background-color: #FFD6E0 !important; box-shadow:none !important; }
[data-testid=\"stToolbar\"], footer, #MainMenu { display:none !important; }
* { font-family: Poppins, sans-serif; }
</style>
""", unsafe_allow_html=True)

st.markdown("""
<div style="text-align:center;padding:3rem 1rem 1.5rem;">
  <p style="font-size:0.8rem;letter-spacing:0.22em;text-transform:uppercase;color:#b5677a;margin-bottom:0.5rem;">✦ a little something for you ✦</p>
  <h1 style="font-family:Playfair Display,serif;font-size:2.8rem;font-weight:700;color:#8B1A3A;line-height:1.25;margin:0;">Happiest Birthday<br>my Hani 🎀</h1>
  <p style="font-size:1.4rem;letter-spacing:6px;margin-top:0.6rem;">🌸 💖 🌸</p>
</div>
""", unsafe_allow_html=True)

flap_t = "rotateX(180deg)" if st.session_state.open else "rotateX(0deg)"
seal_o = "0" if st.session_state.open else "1"

env_html = f"""
<div style="display:flex;justify-content:center;padding:0.5rem 0 0;perspective:800px;">
  <div style="position:relative;width:320px;height:210px;">
    <div style="position:absolute;inset:0;background:#9B1C3A;border-radius:4px 4px 14px 14px;box-shadow:0 8px 28px rgba(139,26,58,0.4);overflow:hidden;">
      <div style="position:absolute;bottom:0;left:0;width:0;height:0;border-bottom:105px solid #b52244;border-right:160px solid transparent;"></div>
      <div style="position:absolute;bottom:0;right:0;width:0;height:0;border-bottom:105px solid #b52244;border-left:160px solid transparent;"></div>
      <div style="position:absolute;bottom:0;left:0;width:0;height:0;border-bottom:128px solid #c4294f;border-left:160px solid transparent;border-right:160px solid transparent;"></div>
      <div style="position:absolute;bottom:10px;left:50%;transform:translateX(-50%);width:42px;height:42px;background:#FFD6E0;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;opacity:{seal_o};">💌</div>
    </div>
    <div style="position:absolute;top:0;left:0;width:0;height:0;border-left:160px solid transparent;border-right:160px solid transparent;border-top:105px solid #7a1530;transform-origin:top center;transform:{flap_t};z-index:3;"></div>
  </div>
</div>
"""
st.markdown(env_html, unsafe_allow_html=True)

_, mid, _ = st.columns([1, 2, 1])
with mid:
    label = "Close 💌" if st.session_state.open else "Open your letter 💌"
    if st.button(label, use_container_width=True):
        st.session_state.open = not st.session_state.open
        st.rerun()

if not st.session_state.open:
    st.markdown('<p style="text-align:center;font-size:0.75rem;color:#b5677a;">tap to open ↑</p>', unsafe_allow_html=True)

if st.session_state.open:
    st.markdown("""
<div style="background:#fff9f5;border-radius:14px;padding:2rem 2rem 1.5rem;max-width:360px;margin:1.2rem auto 0;box-shadow:0 4px 20px rgba(139,26,58,0.15);border:0.5px solid #f0c8d4;text-align:center;">
  <p style="font-family:Playfair Display,serif;font-style:italic;font-size:1.05rem;color:#8B1A3A;margin-bottom:1rem;">My dearest Hani,</p>
  <p style="font-size:0.92rem;color:#5a3040;line-height:1.95;margin:0;">
    Happiest birthday to my <em>ellam ellam</em> 🌸<br><br>
    I'm so glad to have you in my life — you make every ordinary moment feel like something worth remembering.<br><br>
    May Allah bless you with all the happiness, good health, and every beautiful thing you deserve. 🤍<br><br>
    You're my bestesttt friend and I love you loads, loads, loads. 💕
  </p>
  <span style="font-family:Playfair Display,serif;font-style:italic;font-size:1rem;color:#9B1C3A;margin-top:1.2rem;display:block;">with all my love 💖</span>
</div>
""", unsafe_allow_html=True)

st.markdown('<div style="text-align:center;color:#c47a8e;font-size:1rem;letter-spacing:8px;margin:2.5rem 0 1rem;">✦ ✦ ✦</div>', unsafe_allow_html=True)

st.markdown('<p style="text-align:center;font-size:1.45rem;color:#8B1A3A;margin-bottom:0.15rem;font-weight:500;">us, always 📸</p>', unsafe_allow_html=True)
st.markdown('<p style="text-align:center;font-size:0.76rem;color:#b5677a;letter-spacing:0.12em;text-transform:uppercase;margin-bottom:1.2rem;">a little gallery just for you</p>', unsafe_allow_html=True)

photos = [(HAN1, "my hani 🌸"), (HAN2, "besties forever 💕"), (HAN3, "love us 🥰")]
cols = st.columns(3)
for i, (b64, cap) in enumerate(photos):
    with cols[i]:
        html = (
            '<div style="background:white;border-radius:10px;padding:9px 9px 28px;'
            'box-shadow:0 4px 18px rgba(139,26,58,0.14);margin-bottom:12px;">'
            '<img src="data:image/png;base64,' + b64 + '" '
            'style="width:100%;border-radius:6px;object-fit:cover;aspect-ratio:1/1;display:block;"/>'
            '<p style="text-align:center;font-size:0.7rem;color:#b5677a;margin-top:8px;font-style:italic;">' + cap + '</p>'
            '</div>'
        )
        st.markdown(html, unsafe_allow_html=True)

st.markdown('<div style="text-align:center;font-size:0.74rem;color:#c47a8e;margin-top:3rem;letter-spacing:0.08em;padding-bottom:2rem;">made with love, just for you ✦ happy birthday hani 🎀</div>', unsafe_allow_html=True)